START TRANSACTION;

-- Repair LIME SLICE component stock after bogus POS reversal from pos_stock_commit#1507.
-- Target final state:
-- - July opening stock remains 6
-- - July closing stock becomes 6
-- - Old June lot is closed
-- - Only July opening lot remains OPEN with qty 6

-- 1) Remove bogus component movement generated by failed/partial POS reversal.
DELETE FROM inv_component_movement_log
WHERE id = 12019
  AND source_table = 'pos_stock_commit'
  AND source_id = 1507
  AND component_id = 142
  AND movement_type = 'VOID_REVERSE'
  AND qty_in = 1.0000
  AND qty_out = 0.0000;

-- 2) Close old June lot so cutoff month July only keeps July opening lot.
UPDATE inv_component_lot
SET qty_out_total = ROUND(qty_out_total + qty_balance, 4),
    qty_balance   = 0.0000,
    status        = 'CLOSED',
    updated_at    = NOW()
WHERE id = 905
  AND component_id = 142
  AND division_id = 2
  AND location_type = 'BAR'
  AND receipt_date = '2026-06-29';

-- 3) Restore July monthly stock to the correct opening/closing state.
UPDATE inv_component_monthly_stock
SET opening_qty = 6.0000,
    opening_total_value = 2880.00,
    in_qty = 0.0000,
    in_total_value = 0.00,
    out_qty = 0.0000,
    out_total_value = 0.00,
    waste_qty = 0.0000,
    waste_total_value = 0.00,
    spoil_qty = 0.0000,
    spoil_total_value = 0.00,
    adjustment_plus_qty = 0.0000,
    adjustment_plus_total_value = 0.00,
    adjustment_minus_qty = 0.0000,
    adjustment_minus_total_value = 0.00,
    closing_qty = 6.0000,
    avg_cost = 480.000000,
    total_value = 2880.00,
    movement_day_count = 0,
    mutation_count = 1,
    last_movement_date = '2026-07-01',
    last_movement_at = CONCAT('2026-07-01', ' 00:00:00'),
    last_movement_table = 'inv_component_monthly_opening',
    last_movement_id = 231,
    source_mode = 'REBUILD',
    notes = 'Manual repair: reset to July opening after bogus POS reversal cleanup',
    updated_at = NOW()
WHERE id = 1769
  AND month_key = '2026-07-01'
  AND location_type = 'BAR'
  AND division_id = 2
  AND component_id = 142
  AND uom_id = 27;

COMMIT;
